// $input.item(0) refers to the first input item from the previous node
// In Search Rows, all rows come as separate items, so $input.all() returns an array of items
const items = $input.all();

if (!items || items.length === 0) {
  // No pending keywords
  return [];
}

// Only take the first item
return [items[0]];

const emailRegex = /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/;

// Thresholds
const subscriberThreshold = 10000;
const videoThreshold = 100;

return $input.all()
  .map(item => {
    const emails = item.json.emails || [];
    const socials = item.json.social_links || {};

    // Clean email
    let cleanEmail = "";
    if (Array.isArray(emails)) {
      const match = emails
        .map(e => e.match(emailRegex))
        .find(e => e !== null);
      cleanEmail = match ? match[0] : "";
    }

    // Build cleaned item
    const cleanedItem = {
      ...item.json,
      email: cleanEmail,
      instagram: socials.instagram || "",
      twitter: socials.twitter || "",
      tiktok: socials.tiktok || "",
      discord: socials.discord || "",
      facebook: socials.facebook || ""
    };

    return cleanedItem;
  })
  // Filter by thresholds
  .filter(channel => {
    const subs = parseInt(channel.subscribers || "0");
    const vids = parseInt(channel.videos || "0");
    return subs >= subscriberThreshold && vids >= videoThreshold;
  })
  .map(channel => ({ json: channel })); // Wrap each in { json: ... } for n8n

// Get items array from search node
const items = $json.items || [];

// Extract channel IDs safely
const channelIds = items
  .map(item => item.snippet?.channelId)
  .filter(id => id !== undefined);

// Deduplicate
const uniqueChannelIds = [...new Set(channelIds)];

// Create comma separated list for API
const channelIdsString = uniqueChannelIds.join(",");

return [
  {
    json: {
      channelIdsString
    }
  }
];

// Get the items array from the YouTube API response
const channels = $json.items || [];

// Thresholds
const subscriberThreshold = 10000;
const videoThreshold = 100;
const viewThreshold = 500000;

// Regex to extract emails
const emailRegex = /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/;

// Filter and map channels
const passedChannels = channels
    .map(channel => {
        // Existing statistics
        const subs = parseInt(channel.statistics?.subscriberCount || "0");
        const vids = parseInt(channel.statistics?.videoCount || "0");
        const views = parseInt(channel.statistics?.viewCount || "0");

        // Skip channels below thresholds
        if (subs < subscriberThreshold || vids < videoThreshold || views < viewThreshold) {
            return null;
        }

        // Extract emails from description
        const description = channel.brandingSettings?.channel?.description || "";
        const descEmails = (description.match(emailRegex) || []);

        // Combine with any existing emails array
        const existingEmails = channel.emails || [];
        const allEmails = [...existingEmails, ...descEmails].filter(Boolean);
        const cleanEmail = allEmails.length ? allEmails[0] : "";

        // Extract social links if present
        const socials = channel.brandingSettings?.channel?.externalLinks || {};

        return {
            json: {
                retry: false,
                channelId: channel.id,
                title: channel.snippet?.title,
                country: channel.snippet?.country || "",
                subscribers: subs,
                videos: vids,
                views: views,
                email: cleanEmail,
                instagram: socials.instagram || "",
                twitter: socials.twitter || "",
                tiktok: socials.tiktok || "",
                discord: socials.discord || "",
                facebook: socials.facebook || ""
            }
        };
    })
    .filter(channel => channel !== null); // Remove channels that didn't pass thresholds

if (passedChannels.length === 0) {
    return [{ json: { retry: true } }];
}

return passedChannels;
